arguments.argument:
if global.gamePaused=false
{
  if sprite_index=sKraidArm
  {
    if anim=0
    {
      image_index+=animSpeed
      if image_index>=image_number-0.6 {anim=1}
    }
    else if anim=1
    {
      image_index-=animSpeed
      if image_index<=0.6 {anim=2}
    }
    else if anim>=2
    {
      anim+=1
      if anim=9 {anim=0}
    }
  }
}
